const headers = $('getColumnNames').first().json.columns

const row = {};
headers.forEach(h => row[h] = h);

return row;

const baseUrl = $('Edit Fields').first().json.baseUrl

const paginationLength = parseInt($input.first().json.paginationList)

const urlList = []

if(!isNaN(paginationLength)) {
for(let i = 1; i<= paginationLength; i++)
  {
 const url = i === 1 ? baseUrl : `${baseUrl}&page=${i}`;
  urlList.push({ url });
}
}
else urlList.push({baseUrl})


return urlList

const html = $input.first().json.data;

const regex = /href="(\/d\/oferta\/[^"]+)"/g
const urls = new Set();
let match;

while((match = regex.exec(html)) !== null) {
  urls.add("https://www.olx.pl"+match[1])
}

return [...urls].map((u) => {return {json: {url:u}}})

const id = $input.first().json.ID.split(": ")[1];
const title = $input.first().json.title;
const price = $input.first().json.price;
const description = $input.first().json.description;
const parametersObject = {}
for(let i = 0; i<$input.first().json.parameters.length;i++ ) {
  let parameter = $input.first().json.parameters[i];
  if(parameter.includes(":"))
  {
    const [key, value] = parameter.split(": ")
    switch(value) {
      case "Tak": parametersObject[key] = true; break;
      case "Nie": parametersObject[key] = false; break;
      default: parametersObject[key] = value

    }
  } else {
    parametersObject[parameter] = true;
  }
}

  return[
    {json: {
  id: id,
  title: title,
  price: price,
  description: description,
  ...parametersObject
  }}
]

const all = $input.all();
const set = new Set();

for (const item of $input.all()) {

  let param = item.json
  if (!param) continue;

  for (const key of Object.keys(param)) {
    set.add(key);
  }
}

return {
  all,
  columns: [...set]
};

const item =$input.first().json

const keys = Object.keys(item)
let urlSettings = ''

for(const key of keys) {
  const value = item[key]
  switch(key) {
  case "Podkategoria": urlSettings+=`${value}/`; break;
  case "Miasto": urlSettings+=`${value}/?`
  case "Parking": if(Array.isArray(value)) {
      value.forEach((val, index) => {
        urlSettings+=`search[filter_enum_parking][${index}]=${val}&`
      })
    }
      break;
  case "Zwierzęta": if(Array.isArray(value)) {
      value.forEach((val, index) => {
        urlSettings+= `search[filter_enum_pets][${index}]=${val}&`
      })
      break;
    }
  case "Winda": if(Array.isArray(value)) {
      value.forEach((val, index) => {
        urlSettings=`search[filter_enum_winda][${index}]=${val}&`
      })
      break;
    }
  case "Rodzaj zabudowy": if(Array.isArray(value)) {
      value.forEach((val, index) => {
        urlSettings+=`search[filter_enum_builttype][${index}]=${val}&`
      }); break;
    }
  case "Liczba pokoi": if(Array.isArray(value)) {
      value.forEach((val, index) => {
        switch(val) {
          case "1 pokój": urlSettings+=`search[filter_enum_rooms][${index}=one&`; break;
          case "2 pokoje": urlSettings+=`search[filter_enum_rooms][${index}=two&`; break;
          case "3 pokoje": urlSettings+=`search[filter_enum_rooms][${index}=three&`; break;
          case "4 pokoje": urlSettings+=`search[filter_enum_rooms][${index}=four&`; break;
        }
      }); break;
    }
  case "Cena - od": if(value!="0") urlSettings+=`search[filter_float_price:from]=${value}&`; break;
  case "Cena - do": if(value!="0") urlSettings+=`search[filter_float_price:to]=${value}&`; break;
  case "Powierzchnia - od": if(value!="0") urlSettings+=`search[filter_float_m:from]=${value}&`; break;
  case "Powierzchnia - do": if(value!="0") urlSettings+=`search[filter_float_m:to]=${value}&`; break;
  case "Poziom": if(Array.isArray(value)) {
      value.forEach((val, index) => {
        switch(val) {
          case "Suterena": urlSettings+=`search[filter_enum_floor_select][${index}]=floor_-1&`; break;
          case "Parter": urlSettings=`search[filter_enum_floor_select][${index}]=floor_0&`;break;
          case "1": urlSettings=`search[filter_enum_floor_select][${index}]=floor_1&`;break;
          case "2": urlSettings=`search[filter_enum_floor_select][${index}]=floor_2&`;break;
          case "3": urlSettings=`search[filter_enum_floor_select][${index}]=floor_3&`;break;
          case "4": urlSettings=`search[filter_enum_floor_select][${index}]=floor_4&`;break;
          case "5": urlSettings=`search[filter_enum_floor_select][${index}]=floor_5&`;break;
          case "6": urlSettings=`search[filter_enum_floor_select][${index}]=floor_6&`;break;
          case "7": urlSettings=`search[filter_enum_floor_select][${index}]=floor_7&`;break;
          case "8": urlSettings=`search[filter_enum_floor_select][${index}]=floor_8&`;break;
          case "9": urlSettings=`search[filter_enum_floor_select][${index}]=floor_9&`;break;
          case "10": urlSettings=`search[filter_enum_floor_select][${index}]=floor_10&`;break;
          case "Powyżej 10": urlSettings=`search[filter_enum_floor_select][${index}]=floor_11&`;break;
          case "Poddasze": urlSettings=`search[filter_enum_floor_select][${index}]=floor_17&`;break;
        }
      })
    }
    case "Umeblowanie": if(Array.isArray(value)) {
      value.forEach((val, index) => {
        switch(val) {
          case "Tak": urlSettings=`search[filter_enum_furniture][${index}]=yes`
          case "Nie": urlSettings=`search[filter_enum_furniture][${index}]=no`
        }
      })
    }

  }
}

return {urlSettings: urlSettings}
